const WIDTH=160;const HEIGHT=120;const ZOOM=4;let gameInstance=null;function startGame(parentElementId){if(gameInstance){console.warn("Game already running.");return}const config={type:Phaser.AUTO,width:WIDTH,height:HEIGHT,backgroundColor:9483718,scale:{mode:Phaser.Scale.NONE,zoom:ZOOM},physics:{default:"arcade"},render:{pixelArt:true,antialias:false},scene:{preload:preload,create:create,update:update},parent:parentElementId,canvasStyle:"display: block; margin: 0 auto;"};gameInstance=new Phaser.Game(config)}function destroyGame(){if(gameInstance){gameInstance.destroy(true);gameInstance=null}}window.startGame=startGame;window.destroyGame=destroyGame;function preload(){const style=document.createElement("style");style.textContent="@font-face{font-family:'Minecraftia';src:url('Minecraftia.woff2')format('woff2')}";document.head.appendChild(style);this.load.image("chicken","Images/Chicken.png");this.load.image("egglaying","Images/egglaying.png");this.load.image("egg","Images/Egg.png");this.load.image("chick","Images/Chick.png");this.load.spritesheet("hatching","Images/hatching.png",{frameWidth:16,frameHeight:16});document.fonts.load("10px Minecraftia").then(()=>{console.log("Minecraftia font loaded")})}function create(){const scene=this;this.score=0;["chicken","egglaying","egg","chick"].forEach(k=>this.textures.get(k).setFilter(Phaser.Textures.FilterMode.NEAREST));this.menu=true;this.selectedButton=0;this.loading=false;this.eggs=this.add.group();this.chickens=this.add.group();this.mrsChicken=this.add.sprite(35,60,"chicken").setScale(4).setDepth(2);this.chickens.add(this.mrsChicken);const f={fontFamily:"Minecraftia, monospace",fontSize:"8px",color:"#FFF"};const sf={...f,color:"#C98D3F"};this.title1=this.add.text(110,30,"Happy Mrs. Chicken",f).setOrigin(.5);this.title2=this.add.text(110,44,"Remaster!",f).setOrigin(0);this.startText=this.add.text(110,68,"<Start>",f).setOrigin(.5);this.creditsText=this.add.text(110,82,"Credits",f).setOrigin(.5);this.scoreBg=this.add.graphics().setDepth(4).setScrollFactor(0);this.scoreBg.visible=false;this.drawScoreBox=w=>{const x=WIDTH-w-2,y=0;this.scoreBg.clear().setScrollFactor(0).setDepth(4);this.scoreBg.fillStyle(16117736,1);this.scoreBg.fillRect(x,y,w+2,10);this.scoreBg.fillStyle(13208895,1);this.scoreBg.fillRect(x,y+9,w+2,1);this.scoreBg.fillRect(x,y,1,10);this.scoreBg.setVisible(true)};this.scoreText=this.add.text(WIDTH-2,-1,"0",sf).setOrigin(1,0).setDepth(5).setScrollFactor(0).setVisible(false);this.keys=this.input.keyboard.addKeys({up:Phaser.Input.Keyboard.KeyCodes.UP,down:Phaser.Input.Keyboard.KeyCodes.DOWN,z:Phaser.Input.Keyboard.KeyCodes.Z,enter:Phaser.Input.Keyboard.KeyCodes.ENTER});this.input.keyboard.on("keydown-UP",()=>{if(this.menu){this.selectedButton=0;this.startText.setText("<Start>");this.creditsText.setText("Credits")}});this.input.keyboard.on("keydown-DOWN",()=>{if(this.menu){this.selectedButton=1;this.startText.setText("Start");this.creditsText.setText("<Credits>")}});this.input.keyboard.on("keydown-Z",()=>this.handleA());this.input.keyboard.on("keydown-ENTER",()=>this.handleA());this.input.on("pointerdown",()=>this.handleA());this.anims.create({key:"hatch",frames:this.anims.generateFrameNumbers("hatching",{start:0,end:11}),frameRate:6,repeat:0});this.time.addEvent({delay:1e4,loop:true,callback:()=>{if(!this.menu){this.eggs.getChildren().forEach(egg=>{const{x:x,y:y}=egg;egg.destroy();const h=scene.add.sprite(x,y,"hatching").setDepth(2).play("hatch");h.on("animationcomplete",()=>{h.destroy();scene.chickens.add(scene.add.sprite(x,y,"chicken").setDepth(2))})})}}});this.loadingSprite=this.add.sprite(WIDTH-12,HEIGHT-12,"egg").setVisible(false).setDepth(10);this.loadingCam=this.cameras.add(0,0,WIDTH,HEIGHT).setBackgroundColor(1511706).setVisible(false)}function handleMenu(scene){scene.cameras.main.fadeOut(400,23,17,26);scene.time.delayedCall(400,()=>{[scene.title1,scene.title2,scene.startText,scene.creditsText].forEach(t=>t.setVisible(false));scene.mrsChicken.destroy();scene.loadingSprite.setVisible(true);scene.loadingCam.setVisible(true);const imgs=["egg","chick","chicken"];let idx=0;const steps=imgs.length*2;const anim=scene.time.addEvent({delay:500,repeat:steps-1,callback:()=>{scene.loadingSprite.setTexture(imgs[idx]);idx=(idx+1)%imgs.length}});scene.time.delayedCall(500*steps,()=>{anim.remove(false);scene.loadingCam.fadeOut(400,23,17,26);scene.time.delayedCall(400,()=>{scene.loadingCam.setVisible(false);scene.loadingSprite.setVisible(false);scene.cameras.main.fadeIn(400,23,17,26);scene.chickens.add(scene.add.sprite(WIDTH/2,HEIGHT/2,"chicken").setDepth(2));scene.menu=false;scene.loading=false;scene.score=0;scene.scoreText.setText("0").setVisible(true);scene.drawScoreBox(scene.scoreText.width+4)})})})}function handleGame(scene){scene.chickens.getChildren().forEach(ch=>{ch.setTexture("egglaying");ch.x=Phaser.Math.Between(1,WIDTH-1);ch.y=Phaser.Math.Between(1,HEIGHT-1);scene.eggs.add(scene.add.sprite(ch.x,ch.y,"egg").setDepth(1));scene.time.delayedCall(300,()=>{ch.y-=3;ch.setTexture("chicken");if(!scene.menu){scene.score++;scene.scoreText.setText(scene.score);scene.drawScoreBox(scene.scoreText.width+4)}})})}function update(){}Phaser.Scene.prototype.handleA=function(){if(this.menu){if(this.selectedButton===0&&!this.loading){handleMenu(this)}else if(this.selectedButton===1){this.cameras.main.flash(300,255,255,255);const tf={fontFamily:"Minecraftia",fontSize:"8px",color:"#C98D3F"};const msg=this.add.text(WIDTH/2,HEIGHT/2,"Created by Sonicblaston",tf).setOrigin(.5).setDepth(999);const bg=this.add.graphics().setDepth(998);const p=3,w=msg.width+p*2,h=msg.height+p*2;const bx=WIDTH/2-w/2,by=HEIGHT/2-h/2;bg.fillStyle(16117736,1).fillRect(bx,by,w,h);bg.fillStyle(13208895,1);[0,h-1].forEach(y=>bg.fillRect(bx,by+y,w,1));[0,w-1].forEach(x=>bg.fillRect(bx+x,by,1,h));this.time.delayedCall(1500,()=>{msg.destroy();bg.destroy()})}}else{handleGame(this)}};